// v4 §2.3 — decoder for the polyline-encoded Natural Earth boundary
// modules generated by scripts/build_boundaries.py. Returns the same
// shape the v3 code used ({i, n, r: [flat [lon,lat,...] rings]}) plus a
// per-country bbox `b` [minLon,minLat,maxLon,maxLat] for fast
// point-in-polygon prefiltering.

export function decodeRing(str, quant = 1000) {
  const out = [];
  let lon = 0, lat = 0, i = 0;
  const n = str.length;
  while (i < n) {
    for (let k = 0; k < 2; k++) {
      let result = 0, shift = 0, b;
      do {
        b = str.charCodeAt(i++) - 63;
        result |= (b & 0x1f) << shift;
        shift += 5;
      } while (b >= 0x20);
      const delta = (result & 1) ? ~(result >> 1) : (result >> 1);
      if (k === 0) lon += delta; else lat += delta;
    }
    out.push(lon / quant, lat / quant);
  }
  return out;
}

// Decode a whole encoded dataset once; results are cached by reference.
const cache = new Map();
export function decodeBoundaries(encoded) {
  if (cache.has(encoded)) return cache.get(encoded);
  const decoded = encoded.map((c) => ({
    i: c.i, n: c.n, b: c.b, r: c.r.map((ring) => decodeRing(ring)),
  }));
  cache.set(encoded, decoded);
  return decoded;
}

// Point-in-polygon with bbox prefilter (ray casting over flat rings).
// Two correctness details that the old 110m code got wrong:
//  - rings that cross the antimeridian (Russia, Fiji, NZ) span nearly the
//    whole lon range in flat coordinates, which breaks ray casting — those
//    rings are tested in a 0..360 unwrapped space instead;
//  - when several countries match (an enclave like Lesotho sits inside
//    South Africa's outer ring; holes are stored as plain rings), the
//    SMALLEST bbox wins — the most specific containment is the answer.
function ringContains(ring, lat, lon) {
  let minLon = 180, maxLon = -180;
  for (let i = 0; i < ring.length; i += 2) {
    if (ring[i] < minLon) minLon = ring[i];
    if (ring[i] > maxLon) maxLon = ring[i];
  }
  const wrap = maxLon - minLon > 180;
  const px = wrap && lon < 0 ? lon + 360 : lon;
  let inside = false;
  for (let i = 0, j = ring.length - 2; i < ring.length; j = i, i += 2) {
    let xi = ring[i], xj = ring[j];
    if (wrap) { if (xi < 0) xi += 360; if (xj < 0) xj += 360; }
    const yi = ring[i + 1], yj = ring[j + 1];
    if (((yi > lat) !== (yj > lat)) &&
        (px < (xj - xi) * (lat - yi) / ((yj - yi) || 1e-9) + xi)) {
      inside = !inside;
    }
  }
  return inside;
}

export function countryAtPoint(boundaries, lat, lon) {
  let best = null, bestArea = Infinity;
  for (const c of boundaries) {
    if (c.b) {
      const wrapB = c.b[2] - c.b[0] > 180;
      const inLon = wrapB || (lon >= c.b[0] && lon <= c.b[2]);
      if (!inLon || lat < c.b[1] || lat > c.b[3]) continue;
    }
    for (const ring of c.r) {
      if (ringContains(ring, lat, lon)) {
        const area = c.b ? (c.b[2] - c.b[0]) * (c.b[3] - c.b[1]) : Infinity;
        if (area < bestArea) { bestArea = area; best = c; }
        break;
      }
    }
  }
  return best;
}
